class Solution:
    def numberOfPairs(self, nums1, nums2, queries):
        nums2 = nums2[:]
        answer = []
        for q in queries:
            if q[0] == 1:
                _, x, y, val = q
                for i in range(x, y + 1):
                    nums2[i] += val
            else:
                _, tot = q
                cnt = 0
                for a in nums1:
                    for b in nums2:
                        if a + b == tot:
                            cnt += 1
                answer.append(cnt)
        return answer

