var numberOfPairs = function(nums1, nums2, queries) {
    const n2 = nums2.length;
    const blockSize = Math.max(1, Math.floor(Math.sqrt(n2)) + 1);
    const numBlocks = Math.ceil(n2 / blockSize);
    const arr = nums2.slice();
    const lazy = new Array(numBlocks).fill(0);
    const counters = [];
    for (let b = 0; b < numBlocks; b++) counters.push(new Map());
    for (let i = 0; i < n2; i++) {
        const b = Math.floor(i / blockSize);
        const d = counters[b];
        d.set(arr[i], (d.get(arr[i]) || 0) + 1);
    }

    function blockRange(b) {
        const lo = b * blockSize;
        const hi = Math.min(n2, lo + blockSize);
        return [lo, hi];
    }

    function normalize(b) {
        const lz = lazy[b];
        if (lz !== 0) {
            const [lo, hi] = blockRange(b);
            const d = counters[b];
            for (let i = lo; i < hi; i++) {
                const ov = arr[i];
                d.set(ov, d.get(ov) - 1);
                if (d.get(ov) === 0) d.delete(ov);
                const nv = ov + lz;
                arr[i] = nv;
                d.set(nv, (d.get(nv) || 0) + 1);
            }
            lazy[b] = 0;
        }
    }

    function addPoint(i, val, b) {
        const d = counters[b];
        const ov = arr[i];
        d.set(ov, d.get(ov) - 1);
        if (d.get(ov) === 0) d.delete(ov);
        const nv = ov + val;
        arr[i] = nv;
        d.set(nv, (d.get(nv) || 0) + 1);
    }

    function rangeAdd(x, y, val) {
        const bx = Math.floor(x / blockSize);
        const by = Math.floor(y / blockSize);
        if (bx === by) {
            normalize(bx);
            for (let i = x; i <= y; i++) addPoint(i, val, bx);
            return;
        }
        normalize(bx);
        const hi = blockRange(bx)[1];
        for (let i = x; i < hi; i++) addPoint(i, val, bx);

        normalize(by);
        const lo2 = blockRange(by)[0];
        for (let i = lo2; i <= y; i++) addPoint(i, val, by);

        for (let b = bx + 1; b < by; b++) lazy[b] += val;
    }

    function countEqual(target) {
        let total = 0;
        for (let b = 0; b < numBlocks; b++) {
            const need = target - lazy[b];
            total += counters[b].get(need) || 0;
        }
        return total;
    }

    const answer = [];
    for (const q of queries) {
        if (q[0] === 1) {
            rangeAdd(q[1], q[2], q[3]);
        } else {
            const tot = q[1];
            let s = 0;
            for (const v of nums1) s += countEqual(tot - v);
            answer.push(s);
        }
    }
    return answer;
};
